#include <iostream>#include <vector>#include <algorithm> using namespace std; void solve() {    int n;    if (!(cin >> n)) return;    vector<int> p(n + 1);    for (int i = 1; i <= n; i++) {        cin >> p[i];    }     vector<int> diff(n + 3, 0);    for (int i = 1; i <= n; i++) {        int L = i + 1;        int R = (p[i] > i) ? p[i] : n + 1;        if (L <= R) {            diff[L]++;            if (R + 1 < n + 3) {                diff[R + 1]--;            }        }    }     int max_chairs = 0;    int current = 0;    for (int k = 1; k <= n + 1; k++) {        current += diff[k];        if (current > max_chairs) {            max_chairs = current;        }    }     cout << max_chairs << "\n";} int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);    int t;    if (!(cin >> t)) return 0;    while (t--) {        solve();    }    return 0;}